head.script:
	//imports("uiplugin._popup");

	//var pparam = JSON.parse(WebSquare.util.getPopupParam());
	//var guideVido = pparam.data.guideVido;
scwin.guideVidoValue;
scwin.tabNo;
scwin.emplyrId;
scwin.popupParam;
/**
 * 화면 초기화에 필요한 로직을 수행한다.
 */
scwin.initScreen = function() {
	scwin.popupParam=comLib.getPopupParam($p,["guideVido"]);
	var guideVido =scwin.popupParam.guideVido;
	var guideVidoArr = guideVido.split(",");
	if(guideVidoArr.length>1){
		scwin.guideVidoValue = guideVidoArr[0];
		scwin.tabNo = guideVidoArr[1];
	}
	scwin.processUccSso();
}
scwin.processUccSso = function() {
	var option = {action : "/processUccSso.do"
				   , success : "scwin.processUccSsoCallback"
				   , isShowMeg : false
					};
	ajaxLib.executeAjaxSync($p, option);
}
scwin.processUccSsoCallback = function(resBody) {
	if (resBody.message.code == "success") {
			scwin.emplyrId = resBody.emplyrId;
			scwin.VidoViewer(scwin.guideVidoValue,scwin.tabNo);
	}
}
scwin.VidoViewer= function(guideVidoValue,tabNo) {
	tabControl1.setSelectedTabIndex( tabControl1.getTabIndex("tabs_"+tabNo) );
	eval($p.id+"helpVido"+"_"+tabControl1.getTabIndex("tabs_"+tabNo)).setSrc("http://ucc.[BASE_DOMAIN]/ucc/ucc/oas/OasUccAuthChk.do?userSe=POTV&uccId=" + guideVidoValue + "&emplyrId=" + scwin.emplyrId);
	var  tabId= $p.id+"helpVido"+"_"+tabControl1.getTabIndex("tabs_"+tabNo);
	scwin.tabSelect(tabId);
}

scwin.tabSelect = function(tabId) {
	$p.$("#"+tabId).on("load", function(e) {
		$p.$("#"+tabId).attr("style", "width:980px; height:707px; left:auto; display: inline-block;");
	});
}

//수도운영_수도노선설계
scwin.pf5_onclick = function() {
	scwin.VidoViewer('20190226001944','1');
};

//수도운영_유수율관리
scwin.pf7_onclick = function() {
	scwin.VidoViewer('20190303001949','1');
};

//수도운영_운영시설 매핑
scwin.pf9_onclick = function() {
	scwin.VidoViewer('','1');
};
